def cmd_describe(args, admin):
    """Handle the 'describe' subcommand."""
    if not args.topics:
        logger.error("At least one topic name is required for describe command.")
        sys.exit(1)

    descriptions = admin.describe_topics(args.topics)
    for desc in descriptions:
        print(f"\nTopic: {desc['topic']}")
        print(f"  Error Code: {desc.get('error_code', 'N/A')}")
        print(f"  Is Internal: {desc.get('is_internal', 'N/A')}")
        partitions = desc.get("partitions", [])
        print(f"  Partitions: {len(partitions)}")
        for p in partitions:
            print(
                f"    Partition {p['partition']}: "
                f"Leader={p.get('leader', 'N/A')}, "
                f"Replicas={p.get('replicas', [])}, "
                f"ISR={p.get('isr', [])}"
            )


