def build_connection_kwargs(args):
    """Build extra connection kwargs from CLI arguments."""
    kwargs = {}
    if args.security_protocol:
        kwargs["security_protocol"] = args.security_protocol
    if args.sasl_mechanism:
        kwargs["sasl_mechanism"] = args.sasl_mechanism
    if args.sasl_username:
        kwargs["sasl_plain_username"] = args.sasl_username
    if args.sasl_password:
        kwargs["sasl_plain_password"] = args.sasl_password
    if args.ssl_cafile:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    return kwargs


def main():
    """Main entry point."""
    parser = build_parser()
    args = parser.parse_args()

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    if not args.command:
        parser.print_help()
        sys.exit(1)

    connection_kwargs = build_connection_kwargs(args)

    command_handlers = {
        "create": cmd_create,
        "delete": cmd_delete,
        "list": cmd_list,
        "describe": cmd_describe,
        "partitions": cmd_partitions,
        "config": cmd_config,
        "cluster": cmd_cluster,
        "consumer-groups": cmd_consumer_groups,
    }

    admin = None
    try:
        admin = KafkaClusterAdmin(
            bootstrap_servers=args.brokers.split(","),
            client_id=args.client_id,
            **connection_kwargs,
        )

        handler = command_handlers.get(args.command)
        if handler:
            handler(args, admin)
        else:
            logger.error("Unknown command: %s", args.command)
            parser.print_help()
            sys.exit(1)

    except KeyboardInterrupt:
        print("\nOperation cancelled by user.")
        sys.exit(130)
    except Exception as e:
        logger.error("Error: %s", e)
        if args.verbose:
            import traceback
            traceback.print_exc()
        sys.exit(1)
    finally:
        if admin:
            admin.close()


if __name__ == "__main__":
    main()